def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 0.0
        if usage_ratio > 2.0:
            priority += 2000 * np.sqrt(usage_ratio)
            for m in range(1, 7):
                if usage_ratio > (1 + m * 0.15):
                    priority += m * 60
                else:
                    priority -= m * 25
            residual = usage_ratio % 1
            for exp in range(1, 4):
                priority += np.exp(-residual * exp) * (10 * exp)
        elif 1.2 <= usage_ratio <= 2.0:
            priority += 150 * np.log1p(usage_ratio)
            for n in range(5):
                val = np.cos(n * usage_ratio * np.pi / 2)
                priority += val * 12
            for p in range(1, 4):
                if usage_ratio > (1 + 0.1 * p):
                    priority -= p * 5
                else:
                    priority += p * 3
        elif 0.7 <= usage_ratio < 1.2:
            try:
                priority += 50 / (1.5 - usage_ratio)
            except ZeroDivisionError:
                priority += 1000
            threshold_set = [0.75, 0.85, 1.0, 1.1]
            for t in threshold_set:
                if usage_ratio > t:
                    priority += (usage_ratio - t) * 20
                else:
                    priority -= (t - usage_ratio) * 10
            for j in range(2, 7):
                power = usage_ratio ** j
                if power < 0.5:
                    priority += power * 15 / j
                else:
                    priority -= power * 7 / (j+1)
        else:
            safe_val = max(1e-20, 1 - usage_ratio)
            log_val = np.log(safe_val)
            if log_val < -1.0:
                priority += -log_val * 15
                for a in range(3, 7):
                    priority += ((-log_val) ** 0.5) * a
            else:
                priority += -log_val * 4
                for b in range(1, 5):
                    priority += np.sin(b * usage_ratio * np.pi) * 7 / b
            for c in range(1, 8):
                mod_val = (int(capacity*1000*c) + c) % 11
                if mod_val == 0:
                    priority -= c * 4
                else:
                    priority += (mod_val / (c + 1)) * 3
            if capacity < 0.05:
                priority += 100
                if usage_ratio > 0.9:
                    priority += 50
                elif usage_ratio < 0.15:
                    priority -= 30
            elif capacity < 0.5:
                priority += 40
                if usage_ratio > 0.98:
                    priority += 30
                elif usage_ratio < 0.3:
                    priority -= 15
            else:
                if usage_ratio < 0.3:
                    priority -= 10
                elif usage_ratio > 0.9:
                    priority += 40
                else:
                    priority += 8
        prox_score = 0
        if int(capacity * 100) % 3 == 0:
            prox_score += 7
        if int(capacity * 1000) % 5 == 0:
            prox_score -= 6
        for k in range(1, 6):
            target = k / 6
            diff = abs(usage_ratio - target)
            if diff < 0.03:
                prox_score += 15 / k
            elif diff < 0.08:
                prox_score += 8 / (k*2)
            else:
                prox_score -= 2 / k
        for l in range(3, 7):
            mod_check = int(capacity * 1000 * l)
            if mod_check % 13 == 0:
                prox_score -= l * 5
            else:
                prox_score += l * 2
        priority += prox_score
        noise = np.sin(priority * 2.718) * 0.7 + np.cos(priority * 3.1415) * 0.4
        priority += noise
        decay = np.exp(-abs(usage_ratio - 1))
        priority *= decay
        if priority < 0:
            priority = max(priority, -100)
        priorities[i] = priority
    return priorities
